mapper.select:
with query as ( select plainto_tsquery(cast(#{tsConfig} as regconfig), #{question}) as tsq ) select null::bigint as source_id, id::text as item_key, concat('contribution:', id::text) as concept_id, concat('用户反馈：', question) as title, answer as content, concat( '{"question":"', replace(coalesce(question, ''), '"', '\"'), '","confirmedBy":"', replace(coalesce(confirmed_by, ''), '"', '\"'), '"}' ) as metadata_json, array['[用户反馈]']::text[] as source_paths, null::integer as chunk_index, null::boolean as verbatim, ts_rank_cd(question_tsv, query.tsq) * 3.0 + ts_rank_cd(answer_tsv, query.tsq) * 4.0 + ts_rank_cd(corrections_tsv, query.tsq) * 1.5
+ case when lower(question) like #{likeToken} then 3.0 else 0 end + case when lower(answer) like #{likeToken} then 4.0 else 0 end + case when lower(corrections::text) like #{likeToken} then 1.5 else 0 end
as score from contributions cross join query where question_tsv @@ query.tsq or answer_tsv @@ query.tsq or corrections_tsv @@ query.tsq
or lower(question) like #{likeToken} or lower(answer) like #{likeToken} or lower(corrections::text) like #{likeToken}
order by score desc, confirmed_at desc, id desc limit #{limit}
